import type { input } from 'zod';
import { z } from 'zod';

const SQUARESPACE_LOADER = 'sqs';
const RAW_LOADER = 'raw';
const VIMEO_LOADER = 'vimeo';
const YOUTUBE_LOADER = 'youtube';
export const loaderProp = z.enum([SQUARESPACE_LOADER, RAW_LOADER, VIMEO_LOADER, YOUTUBE_LOADER])
  .default(
    SQUARESPACE_LOADER,
  );

export const formatProp = z.enum(['jpg', 'webp']);
export type Format = input<typeof formatProp>;

const widthProp = z.string();
const sizeProp = z.tuple([z.string(), /* media query */ widthProp]);
const sizesProp = z.object({
  mediaQuerySizes: z.array(sizeProp).optional(),
  defaultWidth: widthProp,
});

const imageWidthDescriptorProp = z.string().regex(new RegExp('[0-9]+w'));
const imagePixelDensityDescriptorProp = z.string().regex(new RegExp('[0-9]+x'));
const imageWidthSrcProp = z.tuple([z.string(), imageWidthDescriptorProp]);
const imagePixelDensitySrcProp = z.tuple([z.string(), imagePixelDensityDescriptorProp]);
const srcSetProp = z.array(imageWidthSrcProp).or(z.array(imagePixelDensitySrcProp));

export const CorePropsParser = z.object({
  loader: loaderProp,

  /** Set to "" if decorative */
  alt: z.string(),
  /** Intrinsic image width */
  width: z.number().int().nonnegative(),
  /** Intrinsic image height */
  height: z.number().int().nonnegative(),

  /** CSS class name for img element */
  className: z.string().optional(),
  /** Style object applied on top of default style */
  style: z.object({}).catchall(z.union([z.string(), z.number()])).optional(),
  /** @deprecated Priority of image's loading during page load */
  priority: z.enum(['low', 'high']).optional(),
  /** Specifies whether a browser should load an image immediately or to defer loading of off-screen images until for example the user scrolls near them */
  loading: z.enum(['lazy', 'eager']).optional(),
  /** Priority of image's loading during page load */
  fetchpriority: z.enum(['low', 'high']).optional(),

  /**
   * Callback for the 'load' event or, if image has already loaded (via isomorphism), an immediate
   * callback
   */
  onLoadingComplete: z.function().optional(),

  onError: z.function().optional(),

  /** Enable prop validation */
  debug: z.boolean().optional(),
  /** Additional props are added directly to the img element */
}).catchall(z.unknown());

export const SqsLoaderPropsParser = CorePropsParser.extend({
  /** Image source URL */
  src: z.string(),
  sizes: sizesProp.or(z.string()),
  srcSet: z.never().optional(),
  format: z.never().optional(),
});

export const RawLoaderPropsParser = CorePropsParser.extend({
  /** Image source URL */
  src: z.string(),
  sizes: sizesProp.or(z.string()).optional(),
  srcSet: srcSetProp.or(z.string()).optional(),
  format: z.never().optional(),
});

export const VimeoLoaderPropsParser = CorePropsParser.extend({
  /** Image source URL */
  src: z.string(),
  sizes: sizesProp.or(z.string()).optional(),
  srcSet: z.never().optional(),
  format: formatProp,
});

export const YoutubeLoaderPropsParser = CorePropsParser.extend({
  /** Image source URL */
  src: z.string().optional(),
  sizes: sizesProp.or(z.string()).optional(),
  srcSet: z.never().optional(),
  format: formatProp,
  videoId: z.string(),
});

export type Loader = input<typeof loaderProp>;
export type RawLoader = typeof RAW_LOADER;
export type SquarespaceLoader = typeof SQUARESPACE_LOADER;
export type VimeoLoader = typeof VIMEO_LOADER;
export type YoutubeLoader = typeof YOUTUBE_LOADER;

type SquarespaceLoaderProps<L extends SquarespaceLoader> =
  & { loader?: L }
  & input<typeof SqsLoaderPropsParser>;
type RawLoaderProps<L extends RawLoader> = { loader?: L } & input<typeof RawLoaderPropsParser>;
type VimeoLoaderProps<L extends VimeoLoader> =
  & { loader?: L }
  & input<typeof VimeoLoaderPropsParser>;
type YoutubeLoaderProps<L extends YoutubeLoader> =
  & { loader?: L }
  & input<typeof YoutubeLoaderPropsParser>;

/**
 * See API.md for complete documentation.
 */
export type ImageProps<L extends Loader> = L extends RawLoader ? Readonly<RawLoaderProps<L>>
  : L extends SquarespaceLoader ? Readonly<SquarespaceLoaderProps<L>>
  : L extends VimeoLoader ? Readonly<VimeoLoaderProps<L>>
  : L extends YoutubeLoader ? Readonly<YoutubeLoaderProps<L>>
  : never;
